         excluded: ['.hidden-wrapper:not(.on)'],
         onPreValidate: function(e) {

            // console.log('PreValidate');
         },
         onError: function(e) {

             // if accordion, collapse in first one with error
             if($('.panel-collapse')[0] && $('.form-group.has-error')[0]) {
